INSERT INTO status_messages (content, type) VALUES ('Tip: Use /review/grade to manually check your due cards.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The /stats command displays mastery progress for each of the 28 error types.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: igt --handbook --incremental only regenerates rules for new mistakes.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: You can use ctrl+c during a check to abort the LLM request.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The /undo command supports a count, e.g., /undo 3 to delete three checks.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Your vocabulary vault is stored as a Markdown file for easy reading.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: IGT supports Gemini, Qwen, Deepseek, and Ollama providers.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /practice --count=20 to generate a larger exercise set.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The progress bar in /review shows how many cards remain in your session.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Try igt --assess to determine your CEFR level based on past inputs.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: In the REPL, use up/down arrows to navigate through your input history.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The server runs on port 18964 by default.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: You can find your database file at igt_data.db in the project root.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: IGT uses SM-2 algorithm to schedule your reviews optimally.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /clear to clear the terminal screen while keeping the status bar.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Error types are categorized into Grammar, Vocab, Mechanics, Style, and Clarity.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The /refine section in the output shows a more natural, native-like version.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /review/stats to see your SRS retention rate.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: You can customize models and prompts in lib/igt_config.json.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: IGT creates cloze cards automatically for 1-3 token substitutions.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /vocab --list to view all words in your personal vault.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The /tip section in the response provides general usage advice.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: IGT uses Pro models for handbook generation and Flash models for grammar checks.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: If Ollama is running, try /ollama to switch to local inference.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The /diagnoses array explains exactly why each edit was made.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /handbook --days=30 to generate a monthly summary.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: IGT tracks "sessions" — inputs within 30 minutes are grouped together.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /review/all to practice cards even if they aren''t due yet.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Punctuation and capitalization errors are categorized under "Mechanics".', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: "Word Choice" errors are categorized under "Vocabulary".', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: "Tone & Register" errors are categorized under "Style".', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: "Ambiguity" errors are categorized under "Clarity".', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Use /exit or ctrl+d to safely close the IGT session.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: The status bar updates after every grammar check.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Tip: Check the CHANGELOG.md for the latest feature updates.', 'tip');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "uncopyrightable" is the longest English word that can be written without repeating a letter.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Screeched" is the longest one-syllable word in the English language.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The "dot" over the letter "i" or "j" is called a tittle.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Dreamt" is the only English word that ends in the letters "mt".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: English is the official language of 67 different countries.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: A new word is added to the dictionary approximately every two hours.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The shortest, oldest, and most commonly used word is "I".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Almost" is the longest word in English with all the letters in alphabetical order.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Rhythm" is the longest English word without a real vowel (a, e, i, o, u).', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: A "pangram" sentence is one that contains every letter in the language.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "E" is the most common letter in the English language.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "swims" will be "swims" even when turned upside down.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The symbol "@" is officially called an "asperand" or an "ampersat".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Subject-Verb) Collective nouns like "team" can be singular or plural depending on the dialect.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Prepositions) Ending a sentence with a preposition is actually acceptable in modern English.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Adjectives) There is a standard order for adjectives: opinion, size, age, shape, color, origin, material, purpose.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Pronouns) "They" has been used as a singular pronoun since at least the 14th century.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Verbs) The verb "to be" is the most irregular verb in the English language.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Punctuation) The "interrobang" is a non-standard punctuation mark that combines a question mark and an exclamation point.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The longest word in any of the major English dictionaries is "pneumonoultramicroscopicsilicovolcanoconiosis".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "mortgage" comes from a French word meaning "death pledge".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The words "skunk", "papoose", and "squash" are all Native American in origin.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: Shakespeare added over 1,700 words to the English language.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Goodbye" originally comes from the Old English phrase "God be with ye".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The average person knows about 20,000 to 35,000 words.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: More people have learned English as a second language than there are native speakers.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "set" has the most meanings of any word in English.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Typewriter" is the longest word you can make using only the top row of a QWERTY keyboard.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "checkmate" in chess comes from the Persian phrase "Shah Mat," meaning "the king is helpless."', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Town" is the oldest word in the English language that is still used today.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The most used adjective in English is "good".', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "news" was once considered plural, and you could say "the news are bad."', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: "Oxymoron" is itself an oxymoron; in Greek, "oxys" means sharp and "moros" means stupid.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The word "robot" comes from the Czech word for "forced labor."', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: English used to have grammatical gender (like German or French) until the 1200s.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: The pilcrow (¶) is the symbol used to denote a new paragraph.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Verb Tense) The present perfect tense connects the past to the present.', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Word Form) Adverbs often end in "-ly", but not all of them do (e.g., "fast", "well").', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Comparison) "Unique" technically shouldn''t be compared (no "more unique").', 'grammar_fact');
INSERT INTO status_messages (content, type) VALUES ('Grammar Fact: (Negation) Avoid double negatives in formal writing as they can cancel each other out.', 'grammar_fact');
INSERT INTO status_messages (content, type, author) VALUES ('"The limits of my language mean the limits of my world."', 'quote', 'Ludwig Wittgenstein');
INSERT INTO status_messages (content, type, author) VALUES ('"To have another language is to possess a second soul."', 'quote', 'Charlemagne');
INSERT INTO status_messages (content, type, author) VALUES ('"A different language is a different vision of life."', 'quote', 'Federico Fellini');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is the road map of a culture. It tells you where its people come from and where they are going."', 'quote', 'Rita Mae Brown');
INSERT INTO status_messages (content, type, author) VALUES ('"If you talk to a man in a language he understands, that goes to his head. If you talk to him in his language, that goes to his heart."', 'quote', 'Nelson Mandela');
INSERT INTO status_messages (content, type, author) VALUES ('"One language sets you in a corridor for life. Two languages open every door along the way."', 'quote', 'Frank Smith');
INSERT INTO status_messages (content, type, author) VALUES ('"Learning is a treasure that will follow its owner everywhere."', 'quote', 'Chinese Proverb');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is wine upon the lips."', 'quote', 'Virginia Woolf');
INSERT INTO status_messages (content, type, author) VALUES ('"You can never understand one language until you understand at least two."', 'quote', 'Geoffrey Willans');
INSERT INTO status_messages (content, type, author) VALUES ('"Knowledge of languages is the doorway to wisdom."', 'quote', 'Roger Bacon');
INSERT INTO status_messages (content, type, author) VALUES ('"Language exerts hidden power, like a moon on the tides."', 'quote', 'Rita Mae Brown');
INSERT INTO status_messages (content, type, author) VALUES ('"A man who knows two languages is worth two men."', 'quote', 'French Proverb');
INSERT INTO status_messages (content, type, author) VALUES ('"The more languages you know, the more you are human."', 'quote', 'Tomáš Garrigue Masaryk');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is the light of the mind."', 'quote', 'John Stuart Mill');
INSERT INTO status_messages (content, type, author) VALUES ('"To learn a language is to have one more window from which to look at the world."', 'quote', 'Chinese Proverb');
INSERT INTO status_messages (content, type, author) VALUES ('"Words are a pretext. It is the inner bond that draws one person to another, not words."', 'quote', 'Rumi');
INSERT INTO status_messages (content, type, author) VALUES ('"Change your language and you change your thoughts."', 'quote', 'Karl Albrecht');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is the soul of intellect, and writing is the embodyment of language."', 'quote', 'Samuel Johnson');
INSERT INTO status_messages (content, type, author) VALUES ('"The soul of a people is found in its language."', 'quote', 'Johann Gottfried von Herder');
INSERT INTO status_messages (content, type, author) VALUES ('"Without language, one cannot talk to people and understand them; one cannot share their hopes and aspirations."', 'quote', 'Nelson Mandela');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is the apparel in which your thoughts parade before the public."', 'quote', 'George Crane');
INSERT INTO status_messages (content, type, author) VALUES ('"The beauty of a language is in the words; the spirit is in the grammar."', 'quote', 'Unknown');
INSERT INTO status_messages (content, type, author) VALUES ('"A language is not just a body of vocabulary or a set of grammatical rules. A language is a flash of the human spirit."', 'quote', 'Wade Davis');
INSERT INTO status_messages (content, type, author) VALUES ('"Grammar is the logic of speech, even as logic is the grammar of reason."', 'quote', 'Richard Chenevix Trench');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is the mirror of the mind."', 'quote', 'Noam Chomsky');
INSERT INTO status_messages (content, type, author) VALUES ('"A language is a system of responses of a people to its environment."', 'quote', 'Jose Rizal');
INSERT INTO status_messages (content, type, author) VALUES ('"Words are the small change of thought."', 'quote', 'Jules Renard');
INSERT INTO status_messages (content, type, author) VALUES ('"Language is the key to the heart of the people."', 'quote', 'Unknown');
INSERT INTO status_messages (content, type, author) VALUES ('"Every language is a world. Without it, the world is incomplete."', 'quote', 'Unknown');
INSERT INTO status_messages (content, type, author) VALUES ('"Words are, of course, the most powerful drug used by mankind."', 'quote', 'Rudyard Kipling');
